module RefModule(
  input [n-1:0] addr,
  output [m-1:0] data
);parameter n = 3; // number of address signals
parameter m = 8; // number of data signals
parameter d = 8; // number of data words
parameter w = 8; // number of bits per data word

reg [w-1:0] obf_rom [0:d-1];

initial begin
  // Initialize the ROM with data words
  obf_rom[0] = 8'b00000000;
  obf_rom[1] = 8'b00000001;
  obf_rom[2] = 8'b00000010;
  obf_rom[3] = 8'b00000011;
  obf_rom[4] = 8'b00000100;
  obf_rom[5] = 8'b00000101;
  obf_rom[6] = 8'b00000110;
  obf_rom[7] = 8'b00000111;
end

assign data = obf_rom[addr];

endmodule
